        "set:html": "<p>Use <a href=\"/docs/hooks/usenode/\"><code dir=\"auto\">useNode</code></a> to add a collaborative rich text editor to each task:</p><div class=\"expressive-code\"><figure class=\"frame not-content\"><figcaption class=\"header\"></figcaption><pre data-language=\"tsx\"><code><div class=\"ec-line\"><div class=\"code\"><span style=\"--0:#A626A4;--1:#CD89E1\">const</span><span style=\"--0:#383A42;--1:#ABB2BF\"> { </span><span style=\"--0:#875D01;--1:#E5C07B\">doc</span><span style=\"--0:#383A42;--1:#ABB2BF\"> } </span><span style=\"--0:#016C9A;--1:#56B6C2\">=</span><span style=\"--0:#383A42;--1:#ABB2BF\"> </span><span style=\"--0:#3360C1;--1:#61AFEF\">useNode</span><span style=\"--0:#383A42;--1:#ABB2BF\">(</span><span style=\"--0:#383A42;--1:#E6888F\">TaskSchema</span><span style=\"--0:#383A42;--1:#ABB2BF\">, </span><span style=\"--0:#383A42;--1:#E6888F\">taskId</span><span style=\"--0:#383A42;--1:#ABB2BF\">)</span></div></div><div class=\"ec-line\"><div class=\"code\"><span style=\"--0:#646568;--0fs:italic;--1:#9FA3AA;--1fs:italic\">// Pass doc to TipTap's Collaboration extension</span></div></div></code></pre><div class=\"copy\"><div aria-live=\"polite\"></div><button title=\"Copy to clipboard\" data-copied=\"Copied!\" data-code=\"const { doc } = useNode(TaskSchema, taskId)// Pass doc to TipTap&#x27;s Collaboration extension\"><div></div></button></div></figure></div>"
